    ExpressRecipe(id: 'r12', title: 'Кролик с острой капустой', stageIndex: 2, imageAsset: null, ingredients: ['Филе кролика – 200 г', 'Пекинская капуста – 200 г', 'Огурцы —100 г', 'Острый перец по вкусу', 'Чеснок – 1 зубчик', 'Соевый соус – 2 ст. л.', 'Масло оливковое – Юг', 'Уксус по вкусу', 'Соль, тмин, лавровый лист'], steps: ['Филе кролика порезать кусочками, положить в глубокую кастрюлю, добавить соль, лавровый лист и овощной бульон или просто воду. Накрыть крышкой и тушить до готовности. Пекинскую капусту и огурец нарезать тонкими полосками. Чеснок измельчить, из острого перца удалить семена и также мелко нарезать. Смешать масло, соевый соус и немного уксуса. В заправку добавить чеснок, тмин, острый перец и перемешать. Соединить капусту с получившимся соусом.']),
    ExpressRecipe(id: 'r13', title: 'Куриная печень, тушенная в сливках', stageIndex: 1, imageAsset: null, ingredients: ['Куриная печень —100 г', 'Сливки (9 %) – 50 г', 'Капуста цветная —100 г', 'Брокколи – 100 г', 'Масло – 10 г', 'Чеснок – 1/2 зубчика', 'Соль, свежемолотый черный перец', 'Лавровый лист'], steps: ['Куриную печень слегка обжарить на масле, добавить сливки, соль, перец, лавровый лист и потушить. За пару минут до готовности добавить измельченный чеснок. Цветную капусту и брокколи разобрать на соцветия, приготовить на пару, приправить солью и перцем. Печень и овощи выложить на блюдо и подать к столу.']),
    ExpressRecipe(id: 'r14', title: 'Курица с базиликом и сулугуни', stageIndex: 1, imageAsset: null, ingredients: ['Куриные грудки – 150 г', 'Баклажаны – 200 г', 'Пучок свежего базилика', 'Помидоры – 100 г', 'Сулугуни – 50 г', 'Масло оливковое – 10 г', 'Соль, перец, специи'], steps: ['Курицу нарезать длинными полосками, обжарить, приправить солью, перцем, любимыми специями. Баклажаны нарезать средними дольками и также обжарить. Помидор нарезать так, как вам больше нравится. Базилик можно порвать руками. В тарелку выложить готовое мясо, баклажаны, помидоры, добавить сулугуни, нарезанный кубиками, посыпать базиликом и любой другой зеленью. Подать горячим, чтобы сыр успел слегка растаять.']),
    ExpressRecipe(id: 'r15', title: 'Легкий суп', stageIndex: 2, imageAsset: null, ingredients: ['Брокколи – 100 г', 'Филе индейки – 50 г', 'Помидоры черри – 50 г', 'Чеснок – 1 зубчик', 'Пастернак (средний) – 50 г', 'Петрушка', 'Масло растительное – 10 г', 'Перец черный молотый', 'Овощной бульон (готовый) – 200 мл'], steps: ['В глубокой кастрюле нагреть масло, выложить в нее мелко нарезанный пастернак и тушить 5–7 минут. Чеснок нарезать тонкими пластинами, брокколи разобрать на соцветия и добавить к пастернаку. Еще через 5–7 минут добавить измельченную петрушку, разрезанные на половинки помидоры черри и молотый перец. Добавить бульон.', 'Заранее приготовленное мясо индейки нарезать небольшими кусочками и добавить в суп. Перемешать, накрыть крышкой и довести до кипения. Затем варить на медленном огне до готовности.']),
    ExpressRecipe(id: 'r16', title: 'Лосось с прованскими травами и греческий салат', stageIndex: 2, imageAsset: null, ingredients: ['Филе лосося – 100 г', 'Листья салата – 100 г', 'Огурцы —100 г', 'Помидоры —100 г', 'Сыр фета – 70 г', 'Маслины – 5 шт.', 'Масло оливковое – 10 г', 'Лимонный сок', 'Смесь «Прованские травы»', 'Соль, свежемолотый черный перец'], steps: ['Филе рыбы приправить солью и перцем, обильно посыпать смесью «Прованские травы» и запечь в фольге. Овощи и сыр нарезать кубиками. Салатные листья порвать руками. Добавить маслины. Заправить салат оливковым маслом и лимонным соком.']),
    ExpressRecipe(id: 'r17', title: 'Мидии под сыром с салатом из свежей зелени и огурцов', stageIndex: 0, imageAsset: null, ingredients: ['Мидии под сыром с салатом из свежей зелени и огурцов', 'Мидии —150 г', 'Масло оливковое (для приготовления мидий) – 5 г', 'Сыр (17 %) – 50 г', 'Огурцы (3 средних) – 300 г', 'Пекинская капуста – 100 г', 'Сметана – Юг', 'Смесь «Прованские травы» (для мидий)', 'Соль, перец'], steps: ['Масло раскалить на сковороде, положить в нее мидии, приправить солью, прованскими травами, слегка обжарить. Добавить немного воды и довести до готовности. Переложить мидии в огнеупорную форму, посыпать сыром и запечь.', 'Из огурцов и капусты приготовить салат, заправить сметаной со специями. Подать к запеченным мидиям.']),
