    ExpressRecipe(id: 'r19', title: 'Омлет с лососем', stageIndex: 0, imageAsset: null, ingredients: ['Лосось – 50 г (можно использовать уже готовую рыбу, а можно и сырую)', 'Яйца – 2 шт.', 'Сливки (9 %) – 20 мл', 'Масло подсолнечное рафинированное – 5 г', 'Соль, свежемолотый черный перец', 'Свежая зелень'], steps: ['Мясо лосося порезать небольшими кусочками. Разогреть на сковороде масло и положить рыбу. Пока лосось прогревается, смешать сливки с яйцами. Полученной смесью залить рыбу. Добавить соль и перец. При подаче на стол посыпать свежей зеленью.']),
    ExpressRecipe(id: 'r20', title: 'Омлет с шампиньонами', stageIndex: 1, imageAsset: null, ingredients: ['Шампиньоны свежие —100 г', 'Яйца – 2 шт.', 'Сливки (9 %) – 20 мл', 'Масло подсолнечное рафинированное – Юг', 'Соль, свежемолотый черный перец', 'Свежая зелень'], steps: ['Шампиньоны нарезать тонкими пластинами и обжарить. Яйца взбить со сливками, полученной смесью залить шампиньоны. Приправить солью и перцем. При подаче обильно посыпать любой свежей зеленью.']),
