    ExpressRecipe(id: 'r24', title: 'Рататуй', stageIndex: 2, imageAsset: null, ingredients: ['Баклажаны – 2 шт.', 'Кабачки – 100 г', 'Помидоры – 2 шт.', 'Лук репчатый – 1 шт.', 'Перец болгарский – 1 шт.', 'Перец красный острый – 1 шт.', 'Чеснок – 1 зубчик', 'Соль, черный перец', 'Зелень петрушки и тимьяна – 1 ст. л.', 'Масло оливковое – 1 ст. л.'], steps: ['Баклажаны и молодые кабачки нарезать крупными кусками и обжарить в оливковом масле до золотистой корочки, добавить лук, чеснок и болгарский перец. Помидоры ошпарить кипятком и очистить от кожицы, порезать кубиками и положить к овощам. Добавить соль, черный и острый перец, тимьян и петрушку.', 'Тушить под крышкой 20 минут, затем снять крышку и дать выпариться жидкости в течение 5 минут. Есть можно как в горячем, так и в холодном виде. При желании можно добавить укроп.']),
    ExpressRecipe(id: 'r25', title: 'Салат из капусты, огурца и перца', stageIndex: 1, imageAsset: null, ingredients: ['Капуста белокочанная —100 г'], steps: ['Огурцы —150 г I Болгарский перец – 50 г', 'Соль и перец по вкусу', 'Капусту мелко нашинковать и помять руками. Болгарский перец помыть, очистить, порезать мелкими кубиками. Огурцы также нарезать кубиками. Овощи смешать, добавить измельченный укроп, соль и перец, заправить сметаной.']),
    ExpressRecipe(id: 'r26', title: 'Салат из краснокочанной капусты', stageIndex: 1, imageAsset: null, ingredients: ['Капуста краснокочанная – 100 г', 'Огурец – 100 г', 'Перец болгарский – 100 г', 'Оливковое масло – 10 г', 'Соль, перец'], steps: ['Натереть на крупной терке или нашинковать капусту. Порезать соломкой огурец и болгарский перец. Заправить солью, перцем, оливковым маслом.']),
