    ExpressRecipe(id: 'r28', title: 'Салат из свежих овощей', stageIndex: 0, imageAsset: null, ingredients: ['Огурцы – 150 г', 'Помидоры – 200 г', 'перец зеленый сладкий – 200 г', 'Петрушка, укроп, лук зеленый – 20 г', 'Масло оливковое – 10 г'], steps: ['Приготовьте салат и подайте к рыбе.']),
    ExpressRecipe(id: 'r29', title: 'Салат из сельдерея и краснокочанной капусты', stageIndex: 2, imageAsset: null, ingredients: ['Капуста краснокочанная – 200 г', 'Сельдерей – 100 г', 'Яблоко (среднее) – 1 шт.', 'Чеснок – 1 зубчик', 'Масло оливковое – 5 г', 'Горчица', 'Уксус яблочный', 'Соль по вкусу'], steps: ['Порезать капусту, яблоко и сельдерей. Измельчить чеснок. Для заправки смешать горчицу, уксус и оливковое масло. Все перемешать, посолить по вкусу.']),
    ExpressRecipe(id: 'r30', title: 'Салат из цукини и шампиньонов', stageIndex: 2, imageAsset: null, ingredients: ['Цукини – 150 г (1 шт)', 'Шампиньоны —100 г', 'Моцарелла – 30 г', 'Помидоры черри —100 г', 'Салатные листья – 50 г', 'Лимонный сок', 'Масло оливковое – 1 ст. л.', 'Соус «Бальзамико» – по вкусу', 'Чеснок – 1 зубчик Соль, перец'], steps: ['Цукини вымыть и нарезать тонкими кружочками или длинными полосками. Шампиньоны нарезать пластинками.', 'Для заправки смешать оливковое масло с лимонным соком, солью и измельченным чесноком. Цукини и грибы перемешать с заправкой и оставить мариноваться на 30–40 минут.', 'Моцареллу нарезать кусочками, салат порвать руками, помидоры черри разрезать на две части и добавить к остальным ингредиентам. Все перемешать и приправить черным перцем.']),
    ExpressRecipe(id: 'r31', title: 'Салат с креветками', stageIndex: 2, imageAsset: null, ingredients: ['Помидоры – 200 г', 'Огурцы – 100 г', 'Салат зеленый – 100 г', 'Креветки – 100 г', 'Масло оливковое – 5 г', 'Кунжутные семечки', 'Соль, перец, лимон'], steps: ['Крупно порезать овощи, салат порвать. Вскипятить воду, добавив в нее достаточно соли, красный и черный перец, половинку лимона (сок предварительно выжать в воду). Положить в воду креветки, довести до кипения и варить 5 минут. Очистить креветки от панциря. Смешать овощи и креветки. Посыпать кунжутными семечками и заправить оливковым маслом.']),
    ExpressRecipe(id: 'r32', title: 'Свинина по-китайски', stageIndex: 1, imageAsset: null, ingredients: ['Свинина по-китайски', 'Свинина, вырезка – 150 г', 'Сельдерей (стебли) – 200 г', 'Дайкон —100 г', 'Болгарский перец – 50 г', 'Шампиньоны —100 г', 'Масло – 10 г', 'Чеснок', 'Соевый соус', 'Острый перец'], steps: ['Свинину нарезать тонкими полосками и обжарить на раскаленном масле. Овощи и грибы нарезать соломкой и отправить к мясу. Готовить пару минут. Добавить острый перец, измельченный чеснок и соевый соус. Перемешать и готовить еще пару минут. Главное в этом блюде – чтобы овощи остались слегка хрустящими.']),
    ExpressRecipe(id: 'r33', title: 'Семга на зеленой подушке', stageIndex: 0, imageAsset: null, ingredients: ['Семга —150 г', 'Шпинат – 70 г', 'Рукола – 100 г', 'Оливки – 30 г', 'Масло оливковое – 5 мл', 'Цедра и сок лимона', 'Соль, перец'], steps: ['Рыбу посолить, поперчить, выложить на противень и запечь в заранее разогретой до 180 градусов духовке до готовности.', 'Руколу и шпинат порвать, выложить на блюдо, посолить, поперчить, добавить сок и цедру лимона, оливки, оливковое масло и оставить мариноваться на 5-10 минут.', 'В глубокую тарелку выложить зелень, сверху поместить рыбу и подать с бокалом белого сухого вина.', 'Несмотря на довольно высокое содержание жира, семга – отличный диетический продукт. Дело в том, что ее мясо богато жирными кислотами омега-3, которые контролируют уровень лептина. А именно этот гормон регулирует скорость обмена веществ и способствует метаболизму жиров.']),
    ExpressRecipe(id: 'r34', title: 'Скумбрия с овощами в соевом соусе', stageIndex: 1, imageAsset: null, ingredients: ['Скумбрия – 200 г', 'Брокколи —100 г', 'Капуста цветная —100 г', 'Перец болгарский —100 г', 'Масло кунжутное – 10 г', 'Соевый соус по вкусу', 'Чеснок по вкусу', 'Соль, перец'], steps: ['Скумбрию натереть солью и перцем и запечь в фольге или на гриле.', 'Брокколи и цветную капусту разобрать на соцветия, слегка припустить. Перец нарезать тонкой соломкой. В кунжутное масло добавить соевый соус и измельченный чеснок. Перец и капусту приправить соусом и дать настояться 5-10 минут. На блюдо выложить рыбу и свежий салат.']),
    ExpressRecipe(id: 'r35', title: 'Стейк из баранины с овощами на гриле', stageIndex: 1, imageAsset: null, ingredients: ['Стейк из баранины – 200 г', 'Баклажаны – 50 г', 'Кабачок – 50 г', 'Перец зеленый – 50 г', 'Сельдерей (стебли) – 200 г', 'Масло оливковое – 5 г', 'Соль, перец, розмарин', 'Свежая зелень'], steps: ['Баранину приправить солью, перцем, измельченным розмарином и оставить мариноваться в течение часа, после чего запечь мясо в духовке (можно в фольге, пергаменте, рукаве для запекания) или на гриле.', 'Баклажан, кабачок и зеленый перец нарезать крупными кусками. Добавить соль, перец, сбрызнуть оливковым маслом и также запечь на гриле или в духовке. Сельдерей просто нарезать длинными брусками.', 'Мясо и овощи выложить на блюдо, посыпать свежей зеленью. Идеальным дополнением станет бокал хорошего красного сухого вина.']),
    ExpressRecipe(id: 'r36', title: 'Стейк из семги с брокколи и азиатской заправкой', stageIndex: 0, imageAsset: null, ingredients: ['Стейк из семги – 150 г', 'Брокколи – 250 г', 'Корень свежего имбиря', 'Чеснок – 1 зубчик', 'Свежий красный перец чили – 1/3 шт.', 'Масло оливковое – 5 г', 'Масло кунжутное – 5 г', 'Соевый соус – 10 г', 'Лайм (по вкусу)', 'Бальзамический уксус (по вкусу)'], steps: ['Семгу запечь на гриле. Отварить брокколи в пароварке в течение 6 минут. Тем временем очистить кусочек имбиря и чеснок, натереть их на терке. Разрезать пополам перец чили, удалить семена и мелко нарезать. Из лайма отжать сок. В миске смешать чили, имбирь и чеснок, добавить кунжутное и оливковое масло, соевый соус, бальзамический уксус и сок лайма. Попробовать получившуюся заправку и, если необходимо, сбалансировать вкус: соленым – от соевого соуса, сладким – от бальзамического уксуса, кислым – от лайма и острым – от чили. Готовую брокколи переложить на блюдо, полить заправкой и подавать с семгой.']),
    ExpressRecipe(id: 'r37', title: 'Суп из шпината', stageIndex: 1, imageAsset: null, ingredients: ['Шпинат (замороженный или свежий) – 100 г', 'Овощной бульон – 2 стакана', 'Яйцо – 1 шт.', 'Огурцы – 70 г', 'Лимон —1/4 шт.', 'Чеснок – 1 зубчик', 'Сливки (9 %) – 3 ст. л.', 'Соль'], steps: ['В овощном бульоне отварить свежие листья шпината. Приправить солью, лимонным соком, добавить измельченный чеснок, сливки, вареное яйцо, разрезанное на половинки, и огурец, нарезанный кубиками. При подаче украсить зеленью.']),
    ExpressRecipe(id: 'r38', title: 'Суп-пюре из брокколи', stageIndex: 0, imageAsset: null, ingredients: ['Сыр фета – 50 г', 'Овощной бульон – 200 г', 'Брокколи – 100 г', 'Шпинат – 100 г', 'Масло оливковое – 5 г', 'Соль, перец'], steps: ['Овощи сложить в кастрюлю, налить бульон и варить 10 минут. Блендером довести готовый суп до консистенции пюре и добавить сыр. Тщательно размешать, чтобы сыр разошелся.', 'Приправить солью, перцем, зеленью.']),
